import os
import torch
import numpy as np
from PIL import Image
from pathlib import Path
import copy
import json
import inspect
import glob
from lerobot.policies.pi0 import PI0Policy
from lerobot.policies.factory import make_pre_post_processors
os.environ['HF_HUB_OFFLINE'] = '1'
print('Starting comprehensive preprocess diagnostic for PI0 (step-by-step with merge)...')
policy = PI0Policy.from_pretrained('lerobot/pi0_base')
preprocess, postprocess = make_pre_post_processors(
    policy.config,
    'lerobot/pi0_base',
    preprocessor_overrides={'device_processor': {'device': 'cpu'}}
)
print('\nPreprocess type:', type(preprocess))
print('Preprocess dir:', [x for x in dir(preprocess) if not x.startswith('_')])
for attr_name in ['processors', 'pipeline', 'transforms', 'steps', 'processor']:
    val = getattr(preprocess, attr_name, None)
    print(f'{attr_name}: {type(val).__name__ if val is not None else None}')
    if val is not None and hasattr(val, '__len__'):
        print('  Length:', len(val))
steps = getattr(preprocess, 'processors', getattr(preprocess, 'pipeline', getattr(preprocess, 'transforms', None)))
if steps is not None:
    print('Steps:', [type(s).__name__ for s in steps])
    for i, step in enumerate(steps):
        print(f'Step {i} source summary: {type(step).__name__}')
        try:
            src = inspect.getsource(type(step))
            if 'observation' in src.lower() or 'transition' in src.lower():
                print('  Relevant source snippet:', src[:300])
        except:
            pass
print('\nSearching for error string in lerobot...')
found = False
for root, dirs, files in os.walk('/usr/local/lib/python3.12/dist-packages/lerobot'):
    for file in files:
        if file.endswith('.py'):
            path = os.path.join(root, file)
            try:
                with open(path, 'r') as f:
                    content = f.read()
                    if 'requires an observation in the transition' in content:
                        print('Found in:', path)
                        lines = content.splitlines()
                        for i, line in enumerate(lines):
                            if 'requires an observation' in line:
                                for j in range(max(0, i-3), min(len(lines), i+8)):
                                    print('  ', j, lines[j])
                        found = True
                        break
            except:
                pass
    if found:
        break
if not found:
    print('Error string not found in source')
instruction = 'Add bbq_sauce to the dish on the table.'
rgb = np.random.randint(0, 255, (4, 480, 480, 3), dtype=np.uint8)
def create_images(as_pil=True):
    view_names = ['base_0_rgb', 'left_wrist_0_rgb', 'right_wrist_0_rgb']
    images = {}
    for i, name in enumerate(view_names):
        img_array = rgb[i % 4]
        if as_pil:
            img_pil = Image.fromarray(img_array)
            img_pil = img_pil.resize((224, 224), Image.BILINEAR)
            images[name] = img_pil
        else:
            arr = np.array(Image.fromarray(img_array).resize((224, 224), Image.BILINEAR)).transpose(2, 0, 1).astype(np.float32) / 255.0
            images[name] = torch.from_numpy(arr)
    return images
state_np = np.random.rand(8).astype(np.float32)
state_padded = torch.zeros((1, 32), dtype=torch.float32)
state_padded[0, :8] = torch.from_numpy(state_np)
dummy_action = torch.zeros((1, 32), dtype=torch.float32)
print('\n=== Testing step-by-step combined batch (with observation restore) ===')
def test_batch_variant(name, batch_fn):
    print(f'\nTesting {name}:')
    try:
        batch = batch_fn()
        if hasattr(preprocess, 'processors') and preprocess.processors is not None:
            processors = preprocess.processors
            current = copy.deepcopy(batch)
            for i, proc in enumerate(processors):
                try:
                    current = proc(current)
                except Exception as e:
                    if 'observation' not in current:
                        current['observation'] = copy.deepcopy(batch.get('observation', {}))
                        current = proc(current)
            print(f'  SUCCESS: full preprocess with step-by-step for {name}')
            if 'observation' in current or 'images' in str(current):
                print('  Keys after processing:', list(current.keys()))
            return True
        else:
            out = preprocess(batch)
            print(f'  SUCCESS: full preprocess for {name}')
            return True
    except Exception as e:
        print(f'  FAILED: {type(e).__name__}: {str(e)}')
        return False
variants = [
    ('combined_complementary_pil', lambda: {'observation': {'images': create_images(True), 'state': state_padded}, 'complementary_data': {'task': instruction}, 'action': dummy_action.clone(), 'task': instruction}),
    ('combined_task_pil', lambda: {'observation': {'images': create_images(True), 'state': state_padded}, 'task': instruction, 'action': dummy_action.clone()}),
    ('combined_complementary_list_pil', lambda: {'observation': {'images': create_images(True), 'state': state_padded}, 'complementary_data': {'task': [instruction]}, 'action': dummy_action.clone(), 'task': instruction}),
    ('combined_complementary_tensor', lambda: {'observation': {'images': create_images(False), 'state': state_padded}, 'complementary_data': {'task': instruction}, 'action': dummy_action.clone(), 'task': instruction}),
    ('lang_first_then_merge', lambda: {'observation': {'images': create_images(True), 'state': state_padded}, 'task': instruction, 'action': dummy_action.clone()}),
    ('manual_tokens', lambda: {'observation': {'images': create_images(True), 'state': state_padded, 'language': {'tokens': torch.zeros((1, 256), dtype=torch.long), 'attention_mask': torch.ones((1, 256), dtype=torch.long)}}, 'action': dummy_action.clone(), 'complementary_data': {'task': instruction}, 'task': instruction})
]
success_count = 0
for name, fn in variants:
    if test_batch_variant(name, fn):
        success_count += 1
print(f'\nSUCCESS COUNT: {success_count}/{len(variants)}')
if success_count > 0:
    print('\nFULL PREPROCESS SUCCEEDED in at least one variant - pipeline fix validated.')
else:
    print('\nAll variants failed - further processor inspection needed.')
print('\nTest completed.')
